class PortfolioManager {
    var portfolio: [String: Double] = [:]
    
    func addStock(symbol: String, quantity: Double) {
        portfolio[symbol, default: 0] += quantity
    }
    
    func removeStock(symbol: String, quantity: Double) {
        if let currentQuantity = portfolio[symbol] {
            let newQuantity = currentQuantity - quantity
            if newQuantity <= 0 {
                portfolio.removeValue(forKey: symbol)
            } else {
                portfolio[symbol] = newQuantity
            }
        }
    }
